import{_ as n,o as r,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"G04: 核心產品、競爭優勢與市佔率","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/經營組/G04_核心產品與競爭優勢與市佔率_投資研究員.md","filePath":"32Ｑ題本＿重要/經營組/G04_核心產品與競爭優勢與市佔率_投資研究員.md"}'),i={name:"32Ｑ題本＿重要/經營組/G04_核心產品與競爭優勢與市佔率_投資研究員.md"};function l(s,t,a,g,c,_){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="g04-核心產品、競爭優勢與市佔率" tabindex="-1">G04: 核心產品、競爭優勢與市佔率 <a class="header-anchor" href="#g04-核心產品、競爭優勢與市佔率" aria-label="Permalink to &quot;G04: 核心產品、競爭優勢與市佔率&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-G04</li><li><strong>題目：</strong> 公司的核心產品與服務為何？對比同業具備何種技術或成本優勢？在當前競爭環境中的行業佔有率為何？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「產品定位與市場競爭力分析」。能從產品結構、技術優勢、市佔率與同業對比中，判定公司在產業鏈中的真實位階與競爭力持久性。</li><li><strong>意圖：</strong> 執行「產品競爭力與市場位階審計」。從產品結構（本質是什麼）、技術優勢（為何能贏）、市佔率（贏了多少）三個維度，判定公司的競爭力是「結構性優勢」還是「暫時性領先」。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockRevenue</code> 營收結構、<code>TaiwanStockFinancialStatements</code> 毛利率趨勢。</li><li><strong>【產品定位來源：Annual Report (年報)】</strong>：查閱 <code>業務概況 -&gt; 核心產品</code> 與 <code>產業競爭分析</code>。</li><li><strong>【市佔率校準：同業財報】</strong>：透過 FinMind 或搜尋取得同業營收，計算相對市佔。</li><li><strong>【外部驗證：搜尋】</strong>：檢索同業動態、產業報告、券商分析。</li></ol></li><li><strong>邏輯：</strong> 執行「三維競爭力矩陣」——(1)產品是什麼(結構)、(2)為何能贏(優勢)、(3)贏了多少(市佔)。三者缺一不可。</li><li><strong>來源：</strong> <code>FinMind (營收與財報)</code>, <code>年報 (產品與競爭分析)</code>, <code>同業財報 (市佔對比)</code>, <code>產業報告</code></li></ul><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【產品結構拆解】</strong>：必須量化各產品線佔比與成長趨勢，禁止模糊描述「產品多元」。</li><li><strong>【技術優勢穿透】</strong>：必須具體指出「護城河」的物理載體（專利？認證？規模？客戶黏性？），禁止空泛描述「技術領先」。</li><li><strong>【市佔率量化】</strong>：必須計算公司在整體市場與細分市場的市佔率，與同業進行營收/毛利/成長率對比。</li><li><strong>【相對位階對比】</strong>：列出至少 2-3 家同業的營收、毛利率、成長率，判定公司在產業中的真實排位。</li><li><strong>【描述指標】</strong>：絕對禁用「產品優質」、「市佔領先」。必須量化為具體的「產品線佔比 %」、「毛利率階差 ppt」、「市佔率 %」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【g04-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【G04 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【g04-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【G04 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「產品結構 + 技術優勢 + 市佔位階」三段式結構。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：核心產品具備不可替代性（技術壁壘 + 客戶黏性），市佔率穩步提升，毛利率顯著優於同業。</li><li><strong>A (良)</strong>：產品具備明確優勢，市佔率穩定或小幅成長，毛利率維持在同業前段。</li><li><strong>B (持平)</strong>：產品優勢不明顯或正在被侵蝕，市佔率停滯或下滑，毛利率面臨壓力。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li><li><strong>【證據來源】數據溯源</strong>：必須精確標註數據來源（FinMind/年報/搜尋）。</li></ul>',8)])])}const u=n(i,[["render",l]]);export{h as __pageData,u as default};
